import { useNavigate } from 'react-router-dom';
import { useApp } from '../../context/AppContext';
import { getUserById } from '../../data/users';
import { formatCurrency, formatDate } from '../../lib/utils';
import { Card, CardHeader, CardContent } from '../../components/ui/card';
import { Badge } from '../../components/ui/badge';
import { Button } from '../../components/ui/button';
import { StatCard, EmptyState } from '../../components/shared/shared';
import {
  Calendar, Clock, CreditCard, TrendingUp, Video, BookOpen,
  ArrowRight,
} from 'lucide-react';

export function StudentDashboard() {
  const navigate = useNavigate();
  const { currentUser, getSessions, getAssignments, getWalletBalance } = useApp();

  const sessions = getSessions();
  const assignments = getAssignments();

  const upcomingSessions = sessions
    .filter((s) => s.status === 'upcoming')
    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  const completedSessions = sessions.filter((s) => s.status === 'completed');
  const cancelledSessions = sessions.filter((s) => s.status === 'cancelled');

  const walletBalance = getWalletBalance();

  const gradedAssignments = assignments.filter((a) => a.status === 'graded');
  const gradeMap: Record<string, number> = { 'A+': 4.3, 'A': 4.0, 'A-': 3.7, 'B+': 3.3, 'B': 3.0, 'B-': 2.7, 'C+': 2.3, 'C': 2.0, 'C-': 1.7, 'D+': 1.3, 'D': 1.0, 'F': 0 };
  const avgGrade = gradedAssignments.length > 0
    ? (gradedAssignments.reduce((sum, a) => sum + (gradeMap[a.grade || 'F'] || 0), 0) / gradedAssignments.length).toFixed(1)
    : 'N/A';

  const recentAssignments = assignments
    .sort((a, b) => new Date(b.dueDate).getTime() - new Date(a.dueDate).getTime())
    .slice(0, 3);

  return (
    <div className="space-y-6">
      {/* Welcome */}
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Welcome back, {currentUser.name.split(' ')[0]}!</h1>
        <p className="text-gray-500 mt-1">Here&apos;s your learning overview for today.</p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard
          label="Upcoming Sessions"
          value={upcomingSessions.length}
          icon={<Calendar size={20} />}
          subtext="Next session in your schedule"
        />
        <StatCard
          label="Completed Sessions"
          value={completedSessions.length}
          icon={<Clock size={20} />}
          subtext="Total sessions completed"
        />
        <StatCard
          label="Wallet Balance"
          value={formatCurrency(walletBalance)}
          icon={<CreditCard size={20} />}
          subtext={walletBalance > 0 ? 'Available to book sessions' : 'Top up to book sessions'}
        />
        <StatCard
          label="Average Grade"
          value={avgGrade === 'N/A' ? 'N/A' : avgGrade}
          icon={<TrendingUp size={20} />}
          subtext={gradedAssignments.length > 0 ? `Across ${gradedAssignments.length} assignments` : 'No grades yet'}
        />
      </div>

      {/* Upcoming Sessions */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Calendar size={18} className="text-primary-600" />
              <h2 className="font-semibold text-gray-900">Upcoming Sessions</h2>
            </div>
            <Button variant="ghost" size="sm" onClick={() => navigate('/student/sessions')}>
              View All <ArrowRight size={16} className="ml-1" />
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {upcomingSessions.length === 0 ? (
            <EmptyState
              icon="📅"
              title="No upcoming sessions"
              description="Book a session with a tutor to get started."
              action={
                <Button onClick={() => navigate('/student/find-tutors')}>
                  Find Tutors
                </Button>
              }
            />
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {upcomingSessions.slice(0, 3).map((session) => {
                const tutor = getUserById(session.tutorId);
                return (
                  <div
                    key={session.id}
                    className="border border-gray-200 rounded-lg p-4 hover:border-primary-300 hover:shadow-sm transition-all"
                  >
                    <div className="flex items-center gap-3 mb-3">
                      <div className="w-10 h-10 bg-primary-100 rounded-full flex items-center justify-center">
                        <span className="text-sm font-semibold text-primary-700">
                          {tutor?.name.split(' ').map(n => n[0]).join('')}
                        </span>
                      </div>
                      <div>
                        <p className="font-medium text-gray-900 text-sm">{tutor?.name}</p>
                        <p className="text-xs text-gray-500">{session.subjectId} · {session.topic}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3 text-xs text-gray-500 mb-3">
                      <span className="flex items-center gap-1">
                        <Calendar size={12} />
                        {formatDate(session.date)}
                      </span>
                      <span className="flex items-center gap-1">
                        <Clock size={12} />
                        {session.startTime} - {session.endTime}
                      </span>
                    </div>
                    <Button
                      size="sm"
                      className="w-full"
                      onClick={() => navigate(`/student/sessions/${session.id}/live`)}
                    >
                      <Video size={14} className="mr-1" />
                      Join
                    </Button>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Recent Assignments */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <BookOpen size={18} className="text-primary-600" />
              <h2 className="font-semibold text-gray-900">Recent Assignments</h2>
            </div>
            <Button variant="ghost" size="sm" onClick={() => navigate('/student/assignments')}>
              View All <ArrowRight size={16} className="ml-1" />
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {recentAssignments.length === 0 ? (
            <EmptyState
              icon="📝"
              title="No assignments"
              description="Your tutors will assign work here after sessions."
            />
          ) : (
            <div className="divide-y divide-gray-100">
              {recentAssignments.map((assignment) => {
                const statusVariant =
                  assignment.status === 'graded' ? 'success' :
                  assignment.status === 'submitted' ? 'warning' :
                  'default';
                return (
                  <div key={assignment.id} className="flex items-center justify-between py-3 first:pt-0 last:pb-0">
                    <div className="flex-1 min-w-0">
                      <p className="font-medium text-gray-900 text-sm truncate">{assignment.title}</p>
                      <p className="text-xs text-gray-500">{assignment.subjectId} · Due {formatDate(assignment.dueDate)}</p>
                    </div>
                    <div className="flex items-center gap-3 ml-4">
                      <Badge variant={statusVariant}>
                        {assignment.status.charAt(0).toUpperCase() + assignment.status.slice(1)}
                      </Badge>
                      {assignment.grade && (
                        <span className="text-sm font-semibold text-gray-900">{assignment.grade}</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../../context/AppContext';
import { formatCurrency } from '../../lib/utils';
import { Card, CardHeader, CardContent } from '../../components/ui/card';
import { Badge } from '../../components/ui/badge';
import { Button } from '../../components/ui/button';
import { Input, Select } from '../../components/ui/input';
import { Avatar } from '../../components/ui/avatar';
import { StarRating, EmptyState } from '../../components/shared/shared';
import { Search, Filter, MapPin } from 'lucide-react';

export function FindTutors() {
  const navigate = useNavigate();
  const { tutors, subjects } = useApp();

  const [search, setSearch] = useState('');
  const [subjectFilter, setSubjectFilter] = useState('all');

  const filteredTutors = useMemo(() => {
    return tutors.filter((tutor) => {
      const matchesSearch = search === '' ||
        tutor.name.toLowerCase().includes(search.toLowerCase()) ||
        tutor.bio?.toLowerCase().includes(search.toLowerCase());
      const matchesSubject = subjectFilter === 'all' ||
        tutor.subjects?.includes(subjectFilter);
      return matchesSearch && matchesSubject;
    });
  }, [tutors, search, subjectFilter]);

  const subjectOptions = [
    { value: 'all', label: 'All Subjects' },
    ...subjects.map((s) => ({ value: s.id, label: s.name })),
  ];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Find Tutors</h1>
        <p className="text-gray-500 mt-1">Discover the perfect tutor for your learning journey.</p>
      </div>

      {/* Search & Filter */}
      <Card>
        <CardContent className="py-4">
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="flex-1 relative">
              <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
              <Input
                placeholder="Search tutors by name or bio..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="pl-10"
              />
            </div>
            <div className="w-full sm:w-48">
              <Select
                options={subjectOptions}
                value={subjectFilter}
                onChange={(e) => setSubjectFilter(e.target.value)}
              />
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Tutor Grid */}
      {filteredTutors.length === 0 ? (
        <EmptyState
          icon="🔍"
          title="No tutors found"
          description="Try adjusting your search or filter criteria."
        />
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {filteredTutors.map((tutor) => (
            <Card key={tutor.id} className="hover:shadow-md transition-shadow">
              <CardContent className="p-5">
                <div className="flex items-start gap-4">
                  <Avatar name={tutor.name} size="lg" />
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-2">
                      <div>
                        <h3 className="font-semibold text-gray-900">{tutor.name}</h3>
                        <div className="flex items-center gap-1 text-xs text-gray-500 mt-0.5">
                          <MapPin size={12} />
                          <span>Online</span>
                        </div>
                      </div>
                      <div className="text-right flex-shrink-0">
                        <p className="font-bold text-lg text-primary-700">{formatCurrency(tutor.hourlyRate || 0)}</p>
                        <p className="text-xs text-gray-500">per hour</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2 mt-2">
                      {tutor.rating && <StarRating rating={tutor.rating} size="sm" />}
                      {tutor.reviewCount && (
                        <span className="text-xs text-gray-500">({tutor.reviewCount} reviews)</span>
                      )}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-2">
                      {tutor.subjects?.map((subjId) => {
                        const subj = subjects.find((s) => s.id === subjId);
                        return (
                          <Badge key={subjId} variant="info" className="text-xs">
                            {subj?.name || subjId}
                          </Badge>
                        );
                      })}
                    </div>
                    {tutor.bio && (
                      <p className="text-sm text-gray-600 mt-3 line-clamp-2">
                        {tutor.bio.length > 100 ? tutor.bio.slice(0, 100) + '...' : tutor.bio}
                      </p>
                    )}
                    <div className="mt-4">
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => navigate(`/student/tutors/${tutor.id}`)}
                      >
                        View Profile
                      </Button>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../../context/AppContext';
import { getUserById } from '../../data/users';
import { formatCurrency, formatDate } from '../../lib/utils';
import { Card, CardHeader, CardContent } from '../../components/ui/card';
import { Badge } from '../../components/ui/badge';
import { Button } from '../../components/ui/button';
import { Input, Select, Textarea } from '../../components/ui/input';
import { Avatar } from '../../components/ui/avatar';
import { Dialog } from '../../components/ui/dialog';
import { StarRating, EmptyState } from '../../components/shared/shared';
import {
  Calendar, Clock, DollarSign, BookOpen, GraduationCap,
  Star, MessageSquare, ArrowLeft,
} from 'lucide-react';

export function TutorDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const {
    tutors, subjects, sessions, getReviewsForTutor, currentUserId,
    addPayment, addReview,
  } = useApp();

  const tutor = tutors.find((t) => t.id === id) || getUserById(id || '');

  const [showBookDialog, setShowBookDialog] = useState(false);
  const [selectedSubject, setSelectedSubject] = useState('');
  const [selectedTopic, setSelectedTopic] = useState('');
  const [sessionDate, setSessionDate] = useState('');
  const [sessionTime, setSessionTime] = useState('');

  const [showReviewDialog, setShowReviewDialog] = useState(false);
  const [reviewRating, setReviewRating] = useState(5);
  const [reviewText, setReviewText] = useState('');

  const [booked, setBooked] = useState(false);

  if (!tutor) {
    return (
      <div className="flex flex-col items-center justify-center py-16">
        <h2 className="text-xl font-semibold text-gray-900 mb-2">Tutor not found</h2>
        <p className="text-gray-500 mb-4">The tutor you're looking for doesn't exist.</p>
        <Button onClick={() => navigate('/student/find-tutors')}>Back to Find Tutors</Button>
      </div>
    );
  }

  const reviews = getReviewsForTutor(tutor.id);
  const tutorSessions = sessions.filter((s) => s.tutorId === tutor.id);

  const tutorSubjects = subjects.filter((s) => tutor.subjects?.includes(s.id));
  const selectedSubjectData = subjects.find((s) => s.id === selectedSubject);

  const yearsTeaching = Math.max(1, Math.floor(
    (new Date().getTime() - new Date(tutor.joinedAt).getTime()) / (365 * 24 * 60 * 60 * 1000)
  ));

  const handleBookSession = () => {
    const newPayment = {
      id: `pay-${Date.now()}`,
      userId: currentUserId,
      tutorId: tutor.id,
      amount: tutor.hourlyRate || 0,
      type: 'session_payment' as const,
      status: 'completed' as const,
      date: new Date().toISOString().split('T')[0],
      description: `Session booking: ${selectedSubjectData?.name || selectedSubject} - ${selectedTopic}`,
    };
    addPayment(newPayment);
    setBooked(true);
    setShowBookDialog(false);
    setTimeout(() => setBooked(false), 3000);
  };

  const handleAddReview = () => {
    const newReview = {
      id: `rev-${Date.now()}`,
      tutorId: tutor.id,
      studentId: currentUserId,
      rating: reviewRating,
      text: reviewText,
      date: new Date().toISOString().split('T')[0],
    };
    addReview(newReview);
    setShowReviewDialog(false);
    setReviewRating(5);
    setReviewText('');
  };

  return (
    <div className="space-y-6">
      {/* Back button */}
      <button
        onClick={() => navigate('/student/find-tutors')}
        className="flex items-center gap-1 text-sm text-gray-500 hover:text-gray-700 transition-colors"
      >
        <ArrowLeft size={16} />
        Back to Find Tutors
      </button>

      {/* Booked confirmation */}
      {booked && (
        <div className="bg-green-50 border border-green-200 rounded-lg p-4 text-green-800 text-sm">
          Session booked successfully! The payment has been processed.
        </div>
      )}

      {/* Profile Header */}
      <Card>
        <CardContent className="p-6">
          <div className="flex flex-col sm:flex-row items-start gap-6">
            <Avatar name={tutor.name} size="lg" className="w-20 h-20 text-xl" />
            <div className="flex-1">
              <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                <div>
                  <h1 className="text-2xl font-bold text-gray-900">{tutor.name}</h1>
                  <div className="flex flex-wrap items-center gap-2 mt-1">
                    {tutor.subjects?.map((subjId) => {
                      const subj = subjects.find((s) => s.id === subjId);
                      return (
                        <Badge key={subjId} variant="info">
                          {subj?.name || subjId}
                        </Badge>
                      );
                    })}
                  </div>
                  <div className="flex items-center gap-2 mt-2">
                    {tutor.rating && <StarRating rating={tutor.rating} size="md" />}
                    {tutor.reviewCount && (
                      <span className="text-sm text-gray-500">({tutor.reviewCount} reviews)</span>
                    )}
                  </div>
                </div>
                <Button size="lg" onClick={() => setShowBookDialog(true)}>
                  <Calendar size={18} className="mr-2" />
                  Book a Session
                </Button>
              </div>
              {tutor.bio && (
                <p className="text-gray-600 mt-4 leading-relaxed">{tutor.bio}</p>
              )}
              <div className="grid grid-cols-3 gap-4 mt-6">
                <div className="text-center p-3 bg-gray-50 rounded-lg">
                  <DollarSign size={18} className="mx-auto text-primary-600 mb-1" />
                  <p className="font-semibold text-gray-900">{formatCurrency(tutor.hourlyRate || 0)}</p>
                  <p className="text-xs text-gray-500">per hour</p>
                </div>
                <div className="text-center p-3 bg-gray-50 rounded-lg">
                  <BookOpen size={18} className="mx-auto text-primary-600 mb-1" />
                  <p className="font-semibold text-gray-900">{tutorSessions.length}</p>
                  <p className="text-xs text-gray-500">Total Sessions</p>
                </div>
                <div className="text-center p-3 bg-gray-50 rounded-lg">
                  <GraduationCap size={18} className="mx-auto text-primary-600 mb-1" />
                  <p className="font-semibold text-gray-900">{yearsTeaching}+</p>
                  <p className="text-xs text-gray-500">Years Teaching</p>
                </div>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Reviews */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <MessageSquare size={18} className="text-primary-600" />
              <h2 className="font-semibold text-gray-900">Reviews</h2>
            </div>
            <Button variant="outline" size="sm" onClick={() => setShowReviewDialog(true)}>
              <Star size={14} className="mr-1" />
              Write a Review
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {reviews.length === 0 ? (
            <EmptyState
              icon="⭐"
              title="No reviews yet"
              description="Be the first to review this tutor!"
            />
          ) : (
            <div className="space-y-4">
              {reviews.map((review) => {
                const student = getUserById(review.studentId);
                return (
                  <div key={review.id} className="border border-gray-100 rounded-lg p-4">
                    <div className="flex items-start justify-between">
                      <div className="flex items-center gap-2">
                        <Avatar name={student?.name || 'Student'} size="sm" />
                        <div>
                          <p className="font-medium text-sm text-gray-900">{student?.name}</p>
                          <p className="text-xs text-gray-500">{formatDate(review.date)}</p>
                        </div>
                      </div>
                      <StarRating rating={review.rating} size="sm" />
                    </div>
                    <p className="text-sm text-gray-600 mt-3">{review.text}</p>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Book Session Dialog */}
      <Dialog open={showBookDialog} onClose={() => setShowBookDialog(false)} title="Book a Session">
        <div className="space-y-4">
          <Select
            label="Subject"
            options={[
              { value: '', label: 'Select a subject' },
              ...tutorSubjects.map((s) => ({ value: s.id, label: s.name })),
            ]}
            value={selectedSubject}
            onChange={(e) => {
              setSelectedSubject(e.target.value);
              setSelectedTopic('');
            }}
          />
          {selectedSubject && selectedSubjectData && (
            <Select
              label="Topic"
              options={[
                { value: '', label: 'Select a topic' },
                ...selectedSubjectData.topics.map((t) => ({ value: t, label: t })),
              ]}
              value={selectedTopic}
              onChange={(e) => setSelectedTopic(e.target.value)}
            />
          )}
          <Input
            label="Date"
            type="date"
            value={sessionDate}
            onChange={(e) => setSessionDate(e.target.value)}
          />
          <Input
            label="Time"
            type="time"
            value={sessionTime}
            onChange={(e) => setSessionTime(e.target.value)}
          />
          {selectedSubject && selectedTopic && sessionDate && sessionTime && (
            <div className="bg-gray-50 rounded-lg p-3 text-sm">
              <p className="text-gray-600">Session Summary</p>
              <p className="font-medium text-gray-900 mt-1">{selectedSubjectData?.name} - {selectedTopic}</p>
              <p className="text-gray-500">{formatDate(sessionDate)} at {sessionTime}</p>
              <p className="font-bold text-primary-700 mt-2">{formatCurrency(tutor.hourlyRate || 0)}</p>
            </div>
          )}
          <Button
            className="w-full"
            disabled={!selectedSubject || !selectedTopic || !sessionDate || !sessionTime}
            onClick={handleBookSession}
          >
            Confirm Booking
          </Button>
        </div>
      </Dialog>

      {/* Review Dialog */}
      <Dialog open={showReviewDialog} onClose={() => setShowReviewDialog(false)} title="Write a Review">
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Rating</label>
            <div className="flex gap-1">
              {[1, 2, 3, 4, 5].map((star) => (
                <button
                  key={star}
                  onClick={() => setReviewRating(star)}
                  className={`text-2xl transition-colors ${star <= reviewRating ? 'text-yellow-400' : 'text-gray-300'}`}
                >
                  ★
                </button>
              ))}
            </div>
          </div>
          <Textarea
            label="Your Review"
            placeholder="Share your experience with this tutor..."
            rows={4}
            value={reviewText}
            onChange={(e) => setReviewText(e.target.value)}
          />
          <Button
            className="w-full"
            disabled={!reviewText.trim()}
            onClick={handleAddReview}
          >
            Submit Review
          </Button>
        </div>
      </Dialog>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../../context/AppContext';
import { getUserById } from '../../data/users';
import { formatDate } from '../../lib/utils';
import { Card, CardHeader, CardContent } from '../../components/ui/card';
import { Badge } from '../../components/ui/badge';
import { Button } from '../../components/ui/button';
import { Avatar } from '../../components/ui/avatar';
import { Tabs } from '../../components/ui/tabs';
import { EmptyState } from '../../components/shared/shared';
import {
  Calendar, Clock, Video, Star, MessageSquare,
} from 'lucide-react';

export function StudentSessions() {
  const navigate = useNavigate();
  const { getSessions } = useApp();
  const [activeTab, setActiveTab] = useState('upcoming');

  const sessions = getSessions();

  const upcomingSessions = sessions
    .filter((s) => s.status === 'upcoming')
    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  const completedSessions = sessions
    .filter((s) => s.status === 'completed')
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const cancelledSessions = sessions
    .filter((s) => s.status === 'cancelled')
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const tabs = [
    { id: 'upcoming', label: 'Upcoming', count: upcomingSessions.length },
    { id: 'completed', label: 'Completed', count: completedSessions.length },
    { id: 'cancelled', label: 'Cancelled', count: cancelledSessions.length },
  ];

  const activeSessions = activeTab === 'upcoming' ? upcomingSessions :
    activeTab === 'completed' ? completedSessions : cancelledSessions;

  const isWithin15Min = (session: { date: string; startTime: string }) => {
    const sessionStart = new Date(`${session.date}T${session.startTime}`);
    const now = new Date();
    const diffMs = sessionStart.getTime() - now.getTime();
    return diffMs >= -15 * 60 * 1000 && diffMs <= 60 * 60 * 1000;
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">My Sessions</h1>
        <p className="text-gray-500 mt-1">Manage your tutoring sessions.</p>
      </div>

      <Card>
        <CardHeader className="pb-0">
          <Tabs tabs={tabs} activeTab={activeTab} onChange={setActiveTab} />
        </CardHeader>
        <CardContent>
          {activeSessions.length === 0 ? (
            <EmptyState
              icon="📅"
              title={`No ${activeTab} sessions`}
              description={
                activeTab === 'upcoming'
                  ? 'Book a session with a tutor to get started.'
                  : `You have no ${activeTab} sessions yet.`
              }
              action={
                activeTab === 'upcoming' ? (
                  <Button onClick={() => navigate('/student/find-tutors')}>Find Tutors</Button>
                ) : undefined
              }
            />
          ) : (
            <div className="space-y-3 mt-4">
              {activeSessions.map((session) => {
                const tutor = getUserById(session.tutorId);
                const statusVariant =
                  session.status === 'upcoming' ? 'info' :
                  session.status === 'completed' ? 'success' :
                  'danger';
                return (
                  <div
                    key={session.id}
                    className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 p-4 border border-gray-200 rounded-lg hover:border-primary-200 hover:shadow-sm transition-all"
                  >
                    <div className="flex items-center gap-3">
                      <Avatar name={tutor?.name || 'Tutor'} size="md" />
                      <div>
                        <p className="font-medium text-gray-900">{tutor?.name}</p>
                        <p className="text-sm text-gray-500">
                          {session.subjectId} · {session.topic}
                        </p>
                        <div className="flex items-center gap-3 mt-1 text-xs text-gray-500">
                          <span className="flex items-center gap-1">
                            <Calendar size={12} />
                            {formatDate(session.date)}
                          </span>
                          <span className="flex items-center gap-1">
                            <Clock size={12} />
                            {session.startTime} - {session.endTime}
                          </span>
                        </div>
                      </div>
                    </div>
                    <div className="flex items-center gap-3 sm:flex-shrink-0">
                      <Badge variant={statusVariant}>
                        {session.status.charAt(0).toUpperCase() + session.status.slice(1)}
                      </Badge>
                      {session.status === 'upcoming' && isWithin15Min(session) && (
                        <Button
                          size="sm"
                          onClick={() => navigate(`/student/sessions/${session.id}/live`)}
                        >
                          <Video size={14} className="mr-1" />
                          Join
                        </Button>
                      )}
                      {session.status === 'completed' && (
                        <div className="flex items-center gap-2">
                          {session.notes && (
                            <div className="text-xs text-gray-500 max-w-[200px] truncate hidden md:block">
                              <MessageSquare size={12} className="inline mr-1" />
                              {session.notes}
                            </div>
                          )}
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => navigate(`/student/tutors/${session.tutorId}`)}
                          >
                            <Star size={14} className="mr-1" />
                            Leave Review
                          </Button>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../../context/AppContext';
import { getUserById } from '../../data/users';
import { Avatar } from '../../components/ui/avatar';
import { Button } from '../../components/ui/button';
import { Dialog } from '../../components/ui/dialog';
import {
  Mic, MicOff, Camera, CameraOff, Monitor, MonitorOff,
  Pencil, Send, Phone, Clock,
} from 'lucide-react';

export function StudentSessionRoom() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { sessions, currentUser, updateSessionStatus } = useApp();

  const session = sessions.find((s) => s.id === id);
  const tutor = session ? getUserById(session.tutorId) : null;

  const [elapsed, setElapsed] = useState(0);
  const [showEndDialog, setShowEndDialog] = useState(false);
  const [micOn, setMicOn] = useState(true);
  const [cameraOn, setCameraOn] = useState(true);
  const [screenSharing, setScreenSharing] = useState(false);
  const [whiteboardOpen, setWhiteboardOpen] = useState(false);
  const [message, setMessage] = useState('');

  const [chatMessages, setChatMessages] = useState([
    { id: '1', sender: 'Tutor', text: 'Welcome! Let\'s get started with today\'s topic.', time: 'Just now' },
    { id: '2', sender: 'You', text: 'Hi! I\'m ready. I reviewed the material from last session.', time: 'Just now' },
    { id: '3', sender: 'Tutor', text: 'Great! Let\'s dive into the main concepts.', time: 'Just now' },
  ]);

  const chatEndRef = useRef<HTMLDivElement>(null);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    timerRef.current = setInterval(() => {
      setElapsed((prev) => prev + 1);
    }, 1000);
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages]);

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h > 0 ? h + ':' : ''}${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const handleSendMessage = () => {
    if (!message.trim()) return;
    setChatMessages((prev) => [
      ...prev,
      { id: `msg-${Date.now()}`, sender: 'You', text: message.trim(), time: 'Just now' },
    ]);
    setMessage('');
  };

  const handleEndSession = () => {
    if (session) {
      updateSessionStatus(session.id, 'completed');
    }
    navigate('/student/sessions');
  };

  if (!session) {
    return (
      <div className="flex flex-col items-center justify-center py-16">
        <h2 className="text-xl font-semibold text-gray-900 mb-2">Session not found</h2>
        <p className="text-gray-500 mb-4">This session doesn't exist or has ended.</p>
        <Button onClick={() => navigate('/student/sessions')}>Back to Sessions</Button>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] -m-6">
      {/* Top Bar */}
      <div className="bg-gray-900 text-white px-6 py-3 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <h2 className="font-semibold text-sm">{session.topic}</h2>
          <span className="text-gray-400 text-xs">|</span>
          <span className="text-gray-400 text-xs">{tutor?.name}</span>
        </div>
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1.5 bg-red-600 px-3 py-1 rounded-full text-xs font-mono">
            <Clock size={14} />
            {formatTime(elapsed)}
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col lg:flex-row overflow-hidden">
        {/* Left Panel - Video + Whiteboard */}
        <div className="flex-1 lg:w-[60%] flex flex-col bg-gray-800">
          {/* Video Call Area */}
          <div className="flex-1 relative p-4 flex items-center justify-center">
            <div className="relative w-full max-w-2xl aspect-video bg-gray-700 rounded-xl flex items-center justify-center">
              {/* Tutor Video Simulacrum */}
              <div className="absolute bottom-4 right-4 w-32 aspect-video bg-gray-600 rounded-lg border-2 border-gray-500 flex items-center justify-center">
                <div className="text-center">
                  <Avatar name={currentUser.name} size="md" />
                  <p className="text-white text-xs mt-1">You</p>
                </div>
              </div>
              {/* Main Video (Tutor) */}
              <div className="text-center">
                <div className="w-20 h-20 bg-primary-500 rounded-full flex items-center justify-center mx-auto">
                  <span className="text-2xl font-bold text-white">
                    {tutor?.name.split(' ').map(n => n[0]).join('')}
                  </span>
                </div>
                <p className="text-white font-medium mt-3">{tutor?.name}</p>
                <p className="text-gray-400 text-sm mt-1">Video Call</p>
              </div>
            </div>
          </div>

          {/* Whiteboard */}
          {whiteboardOpen && (
            <div className="h-48 bg-white m-4 rounded-xl border-2 border-gray-300 flex items-center justify-center">
              <div className="text-center">
                <Pencil size={32} className="text-gray-400 mx-auto mb-2" />
                <p className="text-gray-500 font-medium">Whiteboard</p>
                <p className="text-gray-400 text-sm">Draw, type, and collaborate</p>
              </div>
            </div>
          )}
        </div>

        {/* Right Panel - Chat */}
        <div className="lg:w-[40%] bg-white border-l border-gray-200 flex flex-col">
          <div className="px-4 py-3 border-b border-gray-100 font-semibold text-sm text-gray-900">
            Chat
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {chatMessages.map((msg) => (
              <div
                key={msg.id}
                className={`flex ${msg.sender === 'You' ? 'justify-end' : 'justify-start'}`}
              >
                <div
                  className={`max-w-[80%] rounded-xl px-4 py-2 ${
                    msg.sender === 'You'
                      ? 'bg-primary-600 text-white rounded-br-sm'
                      : 'bg-gray-100 text-gray-900 rounded-bl-sm'
                  }`}
                >
                  <p className="text-xs font-semibold mb-0.5 opacity-70">{msg.sender}</p>
                  <p className="text-sm">{msg.text}</p>
                  <p className="text-[10px] mt-1 opacity-60">{msg.time}</p>
                </div>
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>
          <div className="p-3 border-t border-gray-100">
            <div className="flex gap-2">
              <input
                type="text"
                placeholder="Type a message..."
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                className="flex-1 rounded-lg border border-gray-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent"
              />
              <Button size="sm" onClick={handleSendMessage}>
                <Send size={16} />
              </Button>
            </div>
          </div>
        </div>
      </div>

      {/* Bottom Controls */}
      <div className="bg-gray-900 text-white px-6 py-3 flex items-center justify-center gap-4">
        <button
          onClick={() => setMicOn(!micOn)}
          className={`p-3 rounded-full transition-colors ${micOn ? 'bg-gray-700 hover:bg-gray-600' : 'bg-red-600 hover:bg-red-700'}`}
          title={micOn ? 'Mute Mic' : 'Unmute Mic'}
        >
          {micOn ? <Mic size={20} /> : <MicOff size={20} />}
        </button>
        <button
          onClick={() => setCameraOn(!cameraOn)}
          className={`p-3 rounded-full transition-colors ${cameraOn ? 'bg-gray-700 hover:bg-gray-600' : 'bg-red-600 hover:bg-red-700'}`}
          title={cameraOn ? 'Turn Off Camera' : 'Turn On Camera'}
        >
          {cameraOn ? <Camera size={20} /> : <CameraOff size={20} />}
        </button>
        <button
          onClick={() => setScreenSharing(!screenSharing)}
          className={`p-3 rounded-full transition-colors ${screenSharing ? 'bg-primary-600 hover:bg-primary-700' : 'bg-gray-700 hover:bg-gray-600'}`}
          title={screenSharing ? 'Stop Sharing' : 'Share Screen'}
        >
          {screenSharing ? <MonitorOff size={20} /> : <Monitor size={20} />}
        </button>
        <button
          onClick={() => setWhiteboardOpen(!whiteboardOpen)}
          className={`p-3 rounded-full transition-colors ${whiteboardOpen ? 'bg-primary-600 hover:bg-primary-700' : 'bg-gray-700 hover:bg-gray-600'}`}
          title="Toggle Whiteboard"
        >
          <Pencil size={20} />
        </button>
        <div className="w-px h-8 bg-gray-700 mx-2" />
        <button
          onClick={() => setShowEndDialog(true)}
          className="p-3 rounded-full bg-red-600 hover:bg-red-700 transition-colors"
          title="End Session"
        >
          <Phone size={20} className="rotate-[135deg]" />
        </button>
      </div>

      {/* End Session Dialog */}
      <Dialog
        open={showEndDialog}
        onClose={() => setShowEndDialog(false)}
        title="End Session"
      >
        <div className="space-y-4">
          <p className="text-gray-600 text-sm">
            Are you sure you want to end this session? This action cannot be undone.
          </p>
          <div className="flex gap-3 justify-end">
            <Button variant="outline" onClick={() => setShowEndDialog(false)}>
              Cancel
            </Button>
            <Button variant="danger" onClick={handleEndSession}>
              End Session
            </Button>
          </div>
        </div>
      </Dialog>
    </div>
  );
}

import { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { getUserById } from '../../data/users';
import { formatDate } from '../../lib/utils';
import { Card, CardHeader, CardContent } from '../../components/ui/card';
import { Badge } from '../../components/ui/badge';
import { Button } from '../../components/ui/button';
import { Textarea } from '../../components/ui/input';
import { Dialog } from '../../components/ui/dialog';
import { Tabs } from '../../components/ui/tabs';
import { EmptyState } from '../../components/shared/shared';
import {
  ClipboardList, Calendar, Upload, FileText, CheckCircle, Clock,
} from 'lucide-react';

export function StudentAssignments() {
  const { getAssignments, submitAssignment } = useApp();
  const [activeTab, setActiveTab] = useState('pending');
  const [submitDialogId, setSubmitDialogId] = useState<string | null>(null);
  const [submissionText, setSubmissionText] = useState('');

  const assignments = getAssignments();

  const pendingAssignments = assignments
    .filter((a) => a.status === 'pending')
    .sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());
  const submittedAssignments = assignments
    .filter((a) => a.status === 'submitted')
    .sort((a, b) => new Date(b.submittedAt || '').getTime() - new Date(a.submittedAt || '').getTime());
  const gradedAssignments = assignments
    .filter((a) => a.status === 'graded')
    .sort((a, b) => new Date(b.dueDate).getTime() - new Date(a.dueDate).getTime());

  const tabs = [
    { id: 'pending', label: 'Pending', count: pendingAssignments.length },
    { id: 'submitted', label: 'Submitted', count: submittedAssignments.length },
    { id: 'graded', label: 'Graded', count: gradedAssignments.length },
  ];

  const activeAssignments =
    activeTab === 'pending' ? pendingAssignments :
    activeTab === 'submitted' ? submittedAssignments :
    gradedAssignments;

  const handleSubmit = (assignmentId: string) => {
    submitAssignment(assignmentId);
    setSubmitDialogId(null);
    setSubmissionText('');
  };

  const getGradeColor = (grade?: string) => {
    if (!grade) return 'text-gray-500';
    const letter = grade.charAt(0).toUpperCase();
    if (letter === 'A') return 'text-green-600';
    if (letter === 'B') return 'text-blue-600';
    if (letter === 'C') return 'text-yellow-600';
    if (letter === 'D' || letter === 'F') return 'text-red-600';
    return 'text-gray-600';
  };

  const isOverdue = (dueDate: string) => new Date(dueDate) < new Date();

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">My Assignments</h1>
        <p className="text-gray-500 mt-1">Track and submit your assignments.</p>
      </div>

      <Card>
        <CardHeader className="pb-0">
          <Tabs tabs={tabs} activeTab={activeTab} onChange={setActiveTab} />
        </CardHeader>
        <CardContent>
          {activeAssignments.length === 0 ? (
            <EmptyState
              icon="📝"
              title={`No ${activeTab} assignments`}
              description={
                activeTab === 'pending'
                  ? 'All caught up! No pending assignments right now.'
                  : `You have no ${activeTab} assignments yet.`
              }
            />
          ) : (
            <div className="space-y-3 mt-4">
              {activeAssignments.map((assignment) => {
                const tutor = getUserById(assignment.tutorId);
                return (
                  <div
                    key={assignment.id}
                    className="border border-gray-200 rounded-lg p-4 hover:border-primary-200 hover:shadow-sm transition-all"
                  >
                    <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-3">
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <h3 className="font-semibold text-gray-900">{assignment.title}</h3>
                          {activeTab === 'pending' && isOverdue(assignment.dueDate) && (
                            <Badge variant="danger">Overdue</Badge>
                          )}
                          {activeTab === 'submitted' && (
                            <Badge variant="warning">Awaiting Grade</Badge>
                          )}
                        </div>
                        <p className="text-sm text-gray-500 mb-1">
                          {assignment.subjectId} · Tutor: {tutor?.name}
                        </p>
                        <div className="flex items-center gap-3 text-xs text-gray-500 mb-2">
                          <span className="flex items-center gap-1">
                            <Calendar size={12} />
                            Due: {formatDate(assignment.dueDate)}
                          </span>
                          {assignment.submittedAt && (
                            <span className="flex items-center gap-1">
                              <Upload size={12} />
                              Submitted: {formatDate(assignment.submittedAt)}
                            </span>
                          )}
                        </div>
                        <p className="text-sm text-gray-600">{assignment.description}</p>

                        {activeTab === 'graded' && assignment.grade && (
                          <div className="mt-3 p-3 bg-gray-50 rounded-lg">
                            <div className="flex items-center gap-2">
                              <span className={`text-lg font-bold ${getGradeColor(assignment.grade)}`}>
                                {assignment.grade}
                              </span>
                              {assignment.feedback && (
                                <div className="flex-1">
                                  <p className="text-xs text-gray-500">Feedback:</p>
                                  <p className="text-sm text-gray-700">{assignment.feedback}</p>
                                </div>
                              )}
                            </div>
                          </div>
                        )}
                      </div>

                      {activeTab === 'pending' && (
                        <Button
                          size="sm"
                          onClick={() => setSubmitDialogId(assignment.id)}
                          className="flex-shrink-0"
                        >
                          <Upload size={14} className="mr-1" />
                          Submit
                        </Button>
                      )}
                      {activeTab === 'submitted' && (
                        <div className="flex items-center gap-1 text-yellow-600 flex-shrink-0">
                          <Clock size={14} />
                          <span className="text-xs font-medium">Awaiting Grade</span>
                        </div>
                      )}
                      {activeTab === 'graded' && (
                        <div className="flex items-center gap-1 text-green-600 flex-shrink-0">
                          <CheckCircle size={16} />
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Submit Dialog */}
      <Dialog
        open={!!submitDialogId}
        onClose={() => { setSubmitDialogId(null); setSubmissionText(''); }}
        title="Submit Assignment"
      >
        <div className="space-y-4">
          <p className="text-sm text-gray-500">
            Add any notes or comments with your submission.
          </p>
          <Textarea
            label="Submission Notes"
            placeholder="Write any notes for your tutor..."
            rows={4}
            value={submissionText}
            onChange={(e) => setSubmissionText(e.target.value)}
          />
          <div className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg">
            <FileText size={18} className="text-gray-400" />
            <span className="text-sm text-gray-500">Upload file (simulated)</span>
          </div>
          <div className="flex gap-3 justify-end">
            <Button variant="outline" onClick={() => { setSubmitDialogId(null); setSubmissionText(''); }}>
              Cancel
            </Button>
            <Button onClick={() => submitDialogId && handleSubmit(submitDialogId)}>
              Submit Assignment
            </Button>
          </div>
        </div>
      </Dialog>
    </div>
  );
}

import { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { formatCurrency, formatDate } from '../../lib/utils';
import { Card, CardHeader, CardContent } from '../../components/ui/card';
import { Badge } from '../../components/ui/badge';
import { Button } from '../../components/ui/button';
import { Input } from '../../components/ui/input';
import { Dialog } from '../../components/ui/dialog';
import { EmptyState } from '../../components/shared/shared';
import {
  CreditCard, DollarSign, TrendingUp, Plus, ArrowUpRight, ArrowDownRight,
  Wallet, History, RefreshCcw,
} from 'lucide-react';

export function StudentPayments() {
  const { getPayments, getWalletBalance, currentUserId, addPayment } = useApp();

  const payments = getPayments();
  const balance = getWalletBalance();

  const [showTopUp, setShowTopUp] = useState(false);
  const [topUpAmount, setTopUpAmount] = useState('');
  const [topUpSuccess, setTopUpSuccess] = useState(false);

  const handleTopUp = () => {
    const amount = parseFloat(topUpAmount);
    if (isNaN(amount) || amount <= 0) return;

    const newPayment = {
      id: `pay-${Date.now()}`,
      userId: currentUserId,
      tutorId: '',
      amount,
      type: 'wallet_topup' as const,
      status: 'completed' as const,
      date: new Date().toISOString().split('T')[0],
      description: 'Wallet top-up',
    };
    addPayment(newPayment);
    setShowTopUp(false);
    setTopUpAmount('');
    setTopUpSuccess(true);
    setTimeout(() => setTopUpSuccess(false), 3000);
  };

  const sortedPayments = [...payments].sort(
    (a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()
  );

  const now = new Date();
  const thisMonthSpent = payments
    .filter((p) => {
      const payDate = new Date(p.date);
      return (
        p.type === 'session_payment' &&
        p.status === 'completed' &&
        payDate.getMonth() === now.getMonth() &&
        payDate.getFullYear() === now.getFullYear()
      );
    })
    .reduce((sum, p) => sum + p.amount, 0);

  const typeBadgeVariant = (type: string) => {
    switch (type) {
      case 'session_payment': return 'info' as const;
      case 'wallet_topup': return 'success' as const;
      case 'refund': return 'warning' as const;
      case 'payout': return 'default' as const;
      default: return 'default' as const;
    }
  };

  const statusBadgeVariant = (status: string) => {
    switch (status) {
      case 'completed': return 'success' as const;
      case 'pending': return 'warning' as const;
      case 'failed': return 'danger' as const;
      default: return 'default' as const;
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Payments</h1>
        <p className="text-gray-500 mt-1">Manage your wallet and view transactions.</p>
      </div>

      {/* Top-up success */}
      {topUpSuccess && (
        <div className="bg-green-50 border border-green-200 rounded-lg p-4 text-green-800 text-sm">
          Wallet topped up successfully!
        </div>
      )}

      {/* Wallet Balance Card */}
      <Card className="bg-gradient-to-br from-primary-600 to-primary-800 text-white border-0">
        <CardContent className="p-6">
          <div className="flex items-center justify-between">
            <div>
              <div className="flex items-center gap-2 mb-1">
                <Wallet size={20} />
                <p className="text-sm text-primary-100">Wallet Balance</p>
              </div>
              <p className="text-4xl font-bold">{formatCurrency(balance)}</p>
              <p className="text-sm text-primary-200 mt-2">
                Spent this month: {formatCurrency(thisMonthSpent)}
              </p>
            </div>
            <Button
              variant="secondary"
              size="lg"
              className="bg-white text-primary-700 hover:bg-primary-50"
              onClick={() => setShowTopUp(true)}
            >
              <Plus size={18} className="mr-2" />
              Top Up
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Transaction History */}
      <Card>
        <CardHeader>
          <div className="flex items-center gap-2">
            <History size={18} className="text-primary-600" />
            <h2 className="font-semibold text-gray-900">Transaction History</h2>
          </div>
        </CardHeader>
        <CardContent>
          {sortedPayments.length === 0 ? (
            <EmptyState
              icon="💳"
              title="No transactions"
              description="Your payment history will appear here."
            />
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-gray-100">
                    <th className="text-left py-3 px-2 text-xs font-medium text-gray-500 uppercase">Date</th>
                    <th className="text-left py-3 px-2 text-xs font-medium text-gray-500 uppercase">Description</th>
                    <th className="text-left py-3 px-2 text-xs font-medium text-gray-500 uppercase">Amount</th>
                    <th className="text-left py-3 px-2 text-xs font-medium text-gray-500 uppercase">Type</th>
                    <th className="text-left py-3 px-2 text-xs font-medium text-gray-500 uppercase">Status</th>
                  </tr>
                </thead>
                <tbody>
                  {sortedPayments.map((payment) => {
                    const isDebit = payment.type === 'session_payment';
                    return (
                      <tr key={payment.id} className="border-b border-gray-50 hover:bg-gray-50 transition-colors">
                        <td className="py-3 px-2 text-sm text-gray-500">
                          {formatDate(payment.date)}
                        </td>
                        <td className="py-3 px-2 text-sm text-gray-900">
                          {payment.description}
                        </td>
                        <td className="py-3 px-2 text-sm">
                          <span className={`flex items-center gap-1 font-medium ${
                            isDebit ? 'text-red-600' : 'text-green-600'
                          }`}>
                            {isDebit ? (
                              <ArrowDownRight size={14} />
                            ) : (
                              <ArrowUpRight size={14} />
                            )}
                            {isDebit ? '-' : '+'}{formatCurrency(payment.amount)}
                          </span>
                        </td>
                        <td className="py-3 px-2">
                          <Badge variant={typeBadgeVariant(payment.type)}>
                            {payment.type.replace('_', ' ')}
                          </Badge>
                        </td>
                        <td className="py-3 px-2">
                          <Badge variant={statusBadgeVariant(payment.status)}>
                            {payment.status}
                          </Badge>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Top Up Dialog */}
      <Dialog open={showTopUp} onClose={() => setShowTopUp(false)} title="Top Up Wallet">
        <div className="space-y-4">
          <Input
            label="Amount (USD)"
            type="number"
            placeholder="Enter amount..."
            value={topUpAmount}
            onChange={(e) => setTopUpAmount(e.target.value)}
            min="1"
          />
          {topUpAmount && parseFloat(topUpAmount) > 0 && (
            <div className="bg-gray-50 rounded-lg p-3 text-sm">
              <p className="text-gray-500">You are adding:</p>
              <p className="text-2xl font-bold text-primary-700">{formatCurrency(parseFloat(topUpAmount))}</p>
            </div>
          )}
          <div className="flex gap-3 justify-end">
            <Button variant="outline" onClick={() => setShowTopUp(false)}>Cancel</Button>
            <Button onClick={handleTopUp} disabled={!topUpAmount || parseFloat(topUpAmount) <= 0}>
              <CreditCard size={16} className="mr-2" />
              Pay {topUpAmount ? formatCurrency(parseFloat(topUpAmount)) : ''}
            </Button>
          </div>
          <p className="text-xs text-gray-400 text-center">
            This is a simulated payment. No real transaction will occur.
          </p>
        </div>
      </Dialog>
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { useApp } from '../../context/AppContext';
import { getUserById } from '../../data/users';
import { Avatar } from '../../components/ui/avatar';
import { Button } from '../../components/ui/button';
import { EmptyState } from '../../components/shared/shared';
import { MessageSquare, Send, Search } from 'lucide-react';

export function StudentMessages() {
  const { getConversationPartners, getConversationWith, sendMessage } = useApp();

  const [selectedUserId, setSelectedUserId] = useState<string | null>(null);
  const [messageText, setMessageText] = useState('');
  const [localMessages, setLocalMessages] = useState<{ senderId: string; text: string; timestamp: string }[]>([]);

  const chatEndRef = useRef<HTMLDivElement>(null);

  const partners = getConversationPartners();

  useEffect(() => {
    if (selectedUserId) {
      const msgs = getConversationWith(selectedUserId);
      setLocalMessages(
        msgs.map((m) => ({
          senderId: m.senderId,
          text: m.text,
          timestamp: m.timestamp,
        }))
      );
    }
  }, [selectedUserId, getConversationWith]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [localMessages]);

  const selectedUser = selectedUserId ? getUserById(selectedUserId) : null;

  const formatTimestamp = (ts: string) => {
    try {
      const date = new Date(ts);
      const now = new Date();
      const diffMs = now.getTime() - date.getTime();
      const diffHours = diffMs / (1000 * 60 * 60);

      if (diffHours < 24) {
        return date.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });
      }
      return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    } catch {
      return ts;
    }
  };

  const handleSend = () => {
    if (!messageText.trim() || !selectedUserId) return;
    const { currentUserId } = { currentUserId: '' };
    // Use the context's currentUserId through useApp
    sendMessage(selectedUserId, messageText.trim());
    setLocalMessages((prev) => [
      ...prev,
      {
        senderId: 'student-1', // current user
        text: messageText.trim(),
        timestamp: new Date().toISOString(),
      },
    ]);
    setMessageText('');
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Messages</h1>
        <p className="text-gray-500 mt-1">Chat with your tutors.</p>
      </div>

      <div className="flex h-[calc(100vh-260px)] bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
        {/* Conversation List */}
        <div className="w-80 border-r border-gray-200 flex flex-col flex-shrink-0">
          <div className="p-3 border-b border-gray-100">
            <div className="relative">
              <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
              <input
                type="text"
                placeholder="Search conversations..."
                className="w-full pl-9 pr-3 py-2 text-sm rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent"
              />
            </div>
          </div>
          <div className="flex-1 overflow-y-auto">
            {partners.length === 0 ? (
              <div className="p-4 text-center text-sm text-gray-500">
                No conversations yet.
              </div>
            ) : (
              partners.map((partnerId) => {
                const user = getUserById(partnerId);
                const convoMsgs = getConversationWith(partnerId);
                const lastMsg = convoMsgs[convoMsgs.length - 1];
                return (
                  <button
                    key={partnerId}
                    onClick={() => setSelectedUserId(partnerId)}
                    className={`w-full text-left p-3 hover:bg-gray-50 transition-colors border-b border-gray-50 ${
                      selectedUserId === partnerId ? 'bg-primary-50 border-l-2 border-l-primary-600' : ''
                    }`}
                  >
                    <div className="flex items-center gap-3">
                      <Avatar name={user?.name || 'User'} size="md" />
                      <div className="flex-1 min-w-0">
                        <p className="font-medium text-sm text-gray-900 truncate">
                          {user?.name}
                        </p>
                        {lastMsg && (
                          <p className="text-xs text-gray-500 truncate mt-0.5">
                            {lastMsg.text.length > 30
                              ? lastMsg.text.slice(0, 30) + '...'
                              : lastMsg.text}
                          </p>
                        )}
                      </div>
                      {lastMsg && (
                        <span className="text-[10px] text-gray-400 flex-shrink-0">
                          {formatTimestamp(lastMsg.timestamp)}
                        </span>
                      )}
                    </div>
                  </button>
                );
              })
            )}
          </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 flex flex-col">
          {!selectedUser ? (
            <div className="flex-1 flex items-center justify-center">
              <EmptyState
                icon="💬"
                title="Select a conversation"
                description="Choose a conversation from the left to start chatting."
              />
            </div>
          ) : (
            <>
              {/* Chat Header */}
              <div className="px-4 py-3 border-b border-gray-100 flex items-center gap-3">
                <Avatar name={selectedUser.name} size="sm" />
                <div>
                  <p className="font-medium text-sm text-gray-900">{selectedUser.name}</p>
                  <p className="text-xs text-gray-500 capitalize">{selectedUser.role}</p>
                </div>
              </div>

              {/* Messages */}
              <div className="flex-1 overflow-y-auto p-4 space-y-3">
                {localMessages.map((msg, idx) => {
                  const isMine = msg.senderId === 'student-1';
                  return (
                    <div
                      key={idx}
                      className={`flex ${isMine ? 'justify-end' : 'justify-start'}`}
                    >
                      <div
                        className={`max-w-[70%] rounded-xl px-4 py-2 ${
                          isMine
                            ? 'bg-primary-600 text-white rounded-br-sm'
                            : 'bg-gray-100 text-gray-900 rounded-bl-sm'
                        }`}
                      >
                        <p className="text-sm">{msg.text}</p>
                        <p className={`text-[10px] mt-1 ${isMine ? 'text-primary-200' : 'text-gray-400'}`}>
                          {formatTimestamp(msg.timestamp)}
                        </p>
                      </div>
                    </div>
                  );
                })}
                <div ref={chatEndRef} />
              </div>

              {/* Input */}
              <div className="p-3 border-t border-gray-100">
                <div className="flex gap-2">
                  <input
                    type="text"
                    placeholder="Type a message..."
                    value={messageText}
                    onChange={(e) => setMessageText(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                    className="flex-1 rounded-lg border border-gray-300 px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent"
                  />
                  <Button size="sm" onClick={handleSend} disabled={!messageText.trim()}>
                    <Send size={16} />
                  </Button>
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

